body:
Is there any way to optimize code generated by this Verilog? The generated code contains a large loop and many operations, and the calculation is relatively slow.

```verilog
module CrcCalc
#(
    parameter CRC_OUT_WIDTH = 32,
    parameter CRC_IN_WIDTH = 128
)(
    input [CRC_IN_WIDTH-1:0] data_in,
    input [CRC_OUT_WIDTH-1:0] data_init,
    input [CRC_OUT_WIDTH-1:0] data_ploy,
    output [CRC_OUT_WIDTH-1:0] data_out
);

assign data_out = crc_out(data_in, data_init, data_ploy);

function [CRC_OUT_WIDTH-1:0] crc_out;
    input [CRC_IN_WIDTH-1:0] crc_in;
    input [CRC_OUT_WIDTH-1:0] init_value;
    input [CRC_OUT_WIDTH-1:0] crc_ploy;

    integer m;
    integer n;
    reg crc_tmp;

    begin
        crc_out = init_value;
        for (m = CRC_IN_WIDTH - 1; m >= 0; m = m - 1) begin
            crc_tmp = crc_in[m] ^ crc_out[CRC_OUT_WIDTH - 1];
            for (n = CRC_OUT_WIDTH - 1; n > 0; n = n - 1) begin
                crc_out[n] = crc_out[n - 1] ^ (crc_ploy[n] & crc_tmp);
            end 
            crc_out[0] = crc_tmp;
        end 
    end 

endfunction

endmodule
```
